import React, { useState, useEffect, useCallback, useRef } from 'react';
import { puzzles } from './data/puzzles.js';
import {
  getBridgeKey,
  areAdjacent,
  canAddBridge,
  computeCurrentCounts,
  isVictory
} from './utils/hashiLogic.js';

const GRID_SIZE = 40;
const ISLAND_RADIUS = 16;

function App() {
  const [puzzleIndex, setPuzzleIndex] = useState(0);
  const [bridges, setBridges] = useState(new Map());
  const [selectedIsland, setSelectedIsland] = useState(null);
  const [cursorIslandId, setCursorIslandId] = useState(0);
  const [errorMessage, setErrorMessage] = useState(null);
  const [victory, setVictory] = useState(false);
  const [kbSelecting, setKbSelecting] = useState(false);
  const [kbFrom, setKbFrom] = useState(null);

  const currentPuzzle = puzzles[puzzleIndex];
  const islands = currentPuzzle.islands;

  // Reset everything when puzzle changes
  const handlePuzzleChange = (e) => {
    const idx = parseInt(e.target.value, 10);
    setPuzzleIndex(idx);
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
    setKbSelecting(false);
    setKbFrom(null);
  };

  const handleReset = () => {
    setBridges(new Map());
    setSelectedIsland(null);
    setCursorIslandId(0);
    setErrorMessage(null);
    setVictory(false);
    setKbSelecting(false);
    setKbFrom(null);
  };

  // Toggle bridge between two islands: none -> single -> double -> none
  const toggleBridge = useCallback((fromIsland, toIsland, currentBridges) => {
    const key = getBridgeKey(fromIsland, toIsland);
    const current = currentBridges.get(key) || 0;

    if (current === 0) {
      // Try to add single
      const result = canAddBridge(islands, currentBridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        setErrorMessage(result.error);
        return currentBridges;
      }
      setErrorMessage(null);
      const newBridges = new Map(currentBridges);
      newBridges.set(key, 1);
      return newBridges;
    } else if (current === 1) {
      // Try to add second
      const result = canAddBridge(islands, currentBridges, fromIsland, toIsland, 1);
      if (!result.valid) {
        // Can't go to double, cycle to none
        setErrorMessage(null);
        const newBridges = new Map(currentBridges);
        newBridges.delete(key);
        return newBridges;
      }
      setErrorMessage(null);
      const newBridges = new Map(currentBridges);
      newBridges.set(key, 2);
      return newBridges;
    } else {
      // current === 2, cycle to none
      setErrorMessage(null);
      const newBridges = new Map(currentBridges);
      newBridges.delete(key);
      return newBridges;
    }
  }, [islands]);

  // Remove bridge entirely
  const removeBridge = useCallback((fromIsland, toIsland, currentBridges) => {
    const key = getBridgeKey(fromIsland, toIsland);
    const current = currentBridges.get(key) || 0;
    if (current === 0) return currentBridges;
    setErrorMessage(null);
    const newBridges = new Map(currentBridges);
    newBridges.delete(key);
    return newBridges;
  }, []);

  // Handle island click
  const handleIslandClick = (island, e) => {
    if (victory) return;

    const isRightOrCtrl = e.button === 2 || e.ctrlKey;

    if (isRightOrCtrl) {
      // Right-click or Ctrl+click: remove bridge if we have a selection
      if (selectedIsland !== null && selectedIsland.id !== island.id) {
        const newBridges = removeBridge(selectedIsland, island, bridges);
        setBridges(newBridges);
        setSelectedIsland(null);
        setCursorIslandId(islands[0].id);
        checkVictoryState(newBridges);
      } else {
        // Select this island (for right-click removal intent)
        setSelectedIsland(island);
        setCursorIslandId(island.id);
      }
      return;
    }

    if (selectedIsland === null) {
      // First click: select
      setSelectedIsland(island);
      setCursorIslandId(island.id);
      setErrorMessage(null);
    } else if (selectedIsland.id === island.id) {
      // Clicked same island: deselect
      setSelectedIsland(null);
    } else {
      // Second click: toggle bridge
      const newBridges = toggleBridge(selectedIsland, island, bridges);
      setBridges(newBridges);
      setSelectedIsland(null);
      setCursorIslandId(islands[0].id);
      checkVictoryState(newBridges);
    }
  };

  // Handle right-click on bridge lines to remove
  const handleBridgeRightClick = (e, key) => {
    e.preventDefault();
    if (victory) return;
    const current = bridges.get(key) || 0;
    if (current === 0) return;
    setErrorMessage(null);
    const newBridges = new Map(bridges);
    newBridges.delete(key);
    setBridges(newBridges);
    setSelectedIsland(null);
    setCursorIslandId(islands[0].id);
    checkVictoryState(newBridges);
  };

  const checkVictoryState = (newBridges) => {
    if (isVictory(islands, newBridges)) {
      setVictory(true);
    }
  };

  // Prevent context menu on SVG
  const handleContextMenu = (e) => {
    e.preventDefault();
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (victory) return;

      const cursorIsland = islands.find(i => i.id === cursorIslandId);
      if (!cursorIsland) return;

      if (e.key === 'Escape') {
        setKbSelecting(false);
        setKbFrom(null);
        setSelectedIsland(null);
        setErrorMessage(null);
        return;
      }

      if (e.key === 'Enter') {
        if (!kbSelecting) {
          // First Enter: start selecting from current cursor island
          setKbSelecting(true);
          setKbFrom(cursorIsland);
          setSelectedIsland(cursorIsland);
        } else {
          // Second Enter: toggle bridge between kbFrom and current cursor
          if (kbFrom && kbFrom.id !== cursorIslandId) {
            const toIsland = islands.find(i => i.id === cursorIslandId);
            if (toIsland) {
              const newBridges = toggleBridge(kbFrom, toIsland, bridges);
              setBridges(newBridges);
              checkVictoryState(newBridges);
            }
          }
          setKbSelecting(false);
          setKbFrom(null);
          setSelectedIsland(null);
          setCursorIslandId(islands[0].id);
        }
        return;
      }

      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        const nextIsland = findNextIsland(cursorIsland, e.key, islands);
        if (nextIsland) {
          setCursorIslandId(nextIsland.id);
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [cursorIslandId, islands, kbSelecting, kbFrom, bridges, victory, toggleBridge]);

  // Find next island in arrow direction
  function findNextIsland(current, direction, islandList) {
    let candidates = [];

    switch (direction) {
      case 'ArrowUp':
        candidates = islandList.filter(i => i.y < current.y);
        candidates.sort((a, b) => {
          const da = Math.abs(a.x - current.x) + (current.y - a.y);
          const db = Math.abs(b.x - current.x) + (current.y - b.y);
          return da - db;
        });
        break;
      case 'ArrowDown':
        candidates = islandList.filter(i => i.y > current.y);
        candidates.sort((a, b) => {
          const da = Math.abs(a.x - current.x) + (a.y - current.y);
          const db = Math.abs(b.x - current.x) + (b.y - current.y);
          return da - db;
        });
        break;
      case 'ArrowLeft':
        candidates = islandList.filter(i => i.x < current.x);
        candidates.sort((a, b) => {
          const da = (current.x - a.x) + Math.abs(a.y - current.y);
          const db = (current.x - b.x) + Math.abs(b.y - current.y);
          return da - db;
        });
        break;
      case 'ArrowRight':
        candidates = islandList.filter(i => i.x > current.x);
        candidates.sort((a, b) => {
          const da = (a.x - current.x) + Math.abs(a.y - current.y);
          const db = (b.x - current.x) + Math.abs(b.y - current.y);
          return da - db;
        });
        break;
    }

    return candidates.length > 0 ? candidates[0] : null;
  }

  // Render bridges
  const renderBridges = () => {
    const lines = [];
    for (const [key, count] of bridges) {
      if (count === 0) continue;
      const [x1, y1, x2, y2] = key.split(',').map(Number);
      const px1 = x1 * GRID_SIZE;
      const py1 = y1 * GRID_SIZE;
      const px2 = x2 * GRID_SIZE;
      const py2 = y2 * GRID_SIZE;

      if (count === 1) {
        lines.push(
          <line
            key={key}
            x1={px1} y1={py1}
            x2={px2} y2={py2}
            stroke="#0f0"
            strokeWidth="2"
            onContextMenu={(e) => handleBridgeRightClick(e, key)}
            onClick={(e) => {
              if (e.ctrlKey) {
                e.preventDefault();
                if (victory) return;
                const newBridges = new Map(bridges);
                newBridges.delete(key);
                setBridges(newBridges);
                setSelectedIsland(null);
                setCursorIslandId(islands[0].id);
                setErrorMessage(null);
                checkVictoryState(newBridges);
              }
            }}
            style={{ cursor: 'pointer' }}
          />
        );
      } else if (count === 2) {
        const isHorizontal = y1 === y2;
        const offset = 3;
        if (isHorizontal) {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1} y1={py1 - offset}
              x2={px2} y2={py2 - offset}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => {
                if (e.ctrlKey) {
                  e.preventDefault();
                  if (victory) return;
                  const newBridges = new Map(bridges);
                  newBridges.delete(key);
                  setBridges(newBridges);
                  setSelectedIsland(null);
                  setCursorIslandId(islands[0].id);
                  setErrorMessage(null);
                  checkVictoryState(newBridges);
                }
              }}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1} y1={py1 + offset}
              x2={px2} y2={py2 + offset}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => {
                if (e.ctrlKey) {
                  e.preventDefault();
                  if (victory) return;
                  const newBridges = new Map(bridges);
                  newBridges.delete(key);
                  setBridges(newBridges);
                  setSelectedIsland(null);
                  setCursorIslandId(islands[0].id);
                  setErrorMessage(null);
                  checkVictoryState(newBridges);
                }
              }}
              style={{ cursor: 'pointer' }}
            />
          );
        } else {
          lines.push(
            <line
              key={key + '-a'}
              x1={px1 - offset} y1={py1}
              x2={px2 - offset} y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => {
                if (e.ctrlKey) {
                  e.preventDefault();
                  if (victory) return;
                  const newBridges = new Map(bridges);
                  newBridges.delete(key);
                  setBridges(newBridges);
                  setSelectedIsland(null);
                  setCursorIslandId(islands[0].id);
                  setErrorMessage(null);
                  checkVictoryState(newBridges);
                }
              }}
              style={{ cursor: 'pointer' }}
            />
          );
          lines.push(
            <line
              key={key + '-b'}
              x1={px1 + offset} y1={py1}
              x2={px2 + offset} y2={py2}
              stroke="#0f0"
              strokeWidth="2"
              onContextMenu={(e) => handleBridgeRightClick(e, key)}
              onClick={(e) => {
                if (e.ctrlKey) {
                  e.preventDefault();
                  if (victory) return;
                  const newBridges = new Map(bridges);
                  newBridges.delete(key);
                  setBridges(newBridges);
                  setSelectedIsland(null);
                  setCursorIslandId(islands[0].id);
                  setErrorMessage(null);
                  checkVictoryState(newBridges);
                }
              }}
              style={{ cursor: 'pointer' }}
            />
          );
        }
      }
    }
    return lines;
  };

  // Render islands
  const renderIslands = () => {
    return islands.map(island => {
      const px = island.x * GRID_SIZE;
      const py = island.y * GRID_SIZE;
      const isSelected = selectedIsland && selectedIsland.id === island.id;

      return (
        <g key={island.id}>
          <circle
            cx={px}
            cy={py}
            r={ISLAND_RADIUS}
            fill="#000"
            stroke={isSelected ? '#ff0' : '#0f0'}
            strokeWidth={isSelected ? 3 : 2}
            style={{ cursor: 'pointer' }}
            onClick={(e) => handleIslandClick(island, e)}
            onContextMenu={(e) => {
              e.preventDefault();
              handleIslandClick(island, { ...e, button: 2 });
            }}
          />
          <text
            x={px}
            y={py}
            textAnchor="middle"
            dominantBaseline="central"
            fill="#0f0"
            fontSize="14"
            fontFamily="'Courier New', monospace"
            style={{ pointerEvents: 'none' }}
          >
            {island.value}
          </text>
        </g>
      );
    });
  };

  // Render cursor (not a circle - use rect)
  const renderCursor = () => {
    const cursorIsland = islands.find(i => i.id === cursorIslandId);
    if (!cursorIsland) return null;
    const px = cursorIsland.x * GRID_SIZE;
    const py = cursorIsland.y * GRID_SIZE;
    const size = ISLAND_RADIUS + 6;

    return (
      <rect
        x={px - size}
        y={py - size}
        width={size * 2}
        height={size * 2}
        fill="none"
        stroke="#0ff"
        strokeWidth="2"
        strokeDasharray="4 2"
        style={{ pointerEvents: 'none' }}
      />
    );
  };

  return (
    <div className="game-container" onContextMenu={handleContextMenu}>
      <div className="controls">
        <select value={puzzleIndex} onChange={handlePuzzleChange}>
          {puzzles.map((p, idx) => (
            <option key={p.id} value={idx}>{p.name}</option>
          ))}
        </select>
        <button onClick={handleReset}>Reset</button>
      </div>
      {errorMessage && <div className="error-message">{errorMessage}</div>}
      {victory && <div className="victory-banner">SOLVED!</div>}
      <svg
        width="800"
        height="600"
        style={{ backgroundColor: '#000' }}
      >
        {renderBridges()}
        {renderIslands()}
        {renderCursor()}
      </svg>
    </div>
  );
}

export default App;
